def analyze_email_headers(headers):
    results = {
        'spf_result': 'NONE',
        'dkim_result': 'NONE',
        'dmarc_result': 'NONE',
        'originating_ip': None,
        'warnings': []
    }

    # Check Authentication-Results header
    for header in headers:
        if header.get('Authentication-Results'):
            auth_header = header['Authentication-Results']
            if 'spf=pass' in auth_header:
                results['spf_result'] = 'PASS'
            elif 'spf=fail' in auth_header:
                results['spf_result'] = 'FAIL'
                results['warnings'].append('SPF validation failed')

            if 'dkim=pass' in auth_header:
                results['dkim_result'] = 'PASS'
            elif 'dkim=fail' in auth_header:
                results['dkim_result'] = 'FAIL'
                results['warnings'].append('DKIM validation failed')

            if 'dmarc=pass' in auth_header:
                results['dmarc_result'] = 'PASS'
            elif 'dmarc=fail' in auth_header:
                results['dmarc_result'] = 'FAIL'
                results['warnings'].append('DMARC validation failed')

    # Get originating IP from Received headers
    results['originating_ip'] = extract_ip_from_received(headers)

    return results
